    private void displayActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_displayActionPerformed
        Sound s = new Sound();
        s.OptionSound();
        V v = new V();
        String inacc=v.getName();
        DefaultTableModel tableHistory = (DefaultTableModel)historyTable1.getModel();
        BankFunction BF = new BankFunction();
        String databaseURL = "jdbc:ucanaccess://C:\\Users\\User\\Documents\\NetBeansProjects\\UNION BANK SYSTEM\\src\\database\\Userdb.accdb";
                
        try (Connection connection = DriverManager.getConnection(databaseURL)) {
            String ID=BF.UNconvertID(connection,inacc);
                String sql = "select * from Account WHERE accountNumber = ? ";
                PreparedStatement us = connection.prepareStatement(sql);                
                us.setString(1,ID); 
                ResultSet result = us.executeQuery();
                    while(result.next()){
                        int bal=result.getInt("balance");
                        
                    displayAmount.setText("RM"+Double.toString(bal));
                    System.out.println("The amount for "+ID+" is: RM"+bal);  
    
            BF.tableAcc_in(connection,ID,tableHistory);

            BF.tableAcc_out(connection,ID,tableHistory);

                }
                 connection.close();  
                }catch (Exception e){
                System.err.println("Got an exception!");
              
                e.printStackTrace();
                
                System.out.println(e); 
                }
 
        // Sort the table based on transactionID column
        TableRowSorter<DefaultTableModel> sorter = new TableRowSorter<>(tableHistory);
        historyTable1.setRowSorter(sorter);
        sorter.setSortKeys(java.util.Collections.singletonList(new javax.swing.RowSorter.SortKey(0, javax.swing.SortOrder.ASCENDING)));
    
    }//GEN-LAST:event_displayActionPerformed

